import { useState, useRef } from "react";

const LOGO_B64 = "";

const CSI_DIVISIONS = {
  "00":"Procurement & Contracting Requirements","01":"General Requirements",
  "02":"Existing Conditions","03":"Concrete","04":"Masonry","05":"Metals",
  "06":"Wood, Plastics & Composites","07":"Thermal & Moisture Protection",
  "08":"Openings","09":"Finishes","10":"Specialties","11":"Equipment",
  "12":"Furnishings","13":"Special Construction","14":"Conveying Equipment",
  "21":"Fire Suppression","22":"Plumbing","23":"HVAC",
  "25":"Integrated Automation","26":"Electrical","27":"Communications",
  "28":"Electronic Safety & Security","31":"Earthwork","32":"Exterior Improvements",
  "33":"Utilities","34":"Transportation","35":"Waterway & Marine Construction",
  "40":"Process Integration","41":"Material Processing & Handling",
  "48":"Electrical Power Generation",
};

const DIV_COLORS = {
  "00":"#8C7B6B","01":"#8C7B6B","02":"#7D6244","03":"#9E9489","04":"#B8956A",
  "05":"#4A7C6F","06":"#5C7A50","07":"#4A6E8A","08":"#7A5F8A","09":"#8A4A68",
  "10":"#A35050","11":"#C47830","12":"#3D7A8A","13":"#6A4A8A","14":"#4A4A8A",
  "21":"#A35050","22":"#3D5CA3","23":"#B86030","25":"#6040A0","26":"#B8960A",
  "27":"#2A7080","28":"#903030","31":"#6B4A1E","32":"#2A6040","33":"#2A3A8A",
  "34":"#4A4A4A","35":"#1A5A7A","40":"#581C87","41":"#5A3010","48":"#7A4010",
};

const SYSTEM_PROMPT = `You are a senior construction estimator with deep expertise in CSI MasterFormat 2020. Analyze this construction plan and identify EVERY element visible. Assign each to the correct CSI Division (00-49). Return ONLY valid JSON, no markdown:
{"planDescription":"...","pageInfo":"...","divisions":{"03":{"name":"Concrete","items":[{"item":"...","detail":"...","location":"..."}]}},"uncategorized":[],"totalItemCount":0}
Include everything visible. General notes=Div 01. Existing/demo=Div 02. Be exhaustive.`;

function loadPdfJs() {
  return new Promise((resolve, reject) => {
    if (window.pdfjsLib) { resolve(window.pdfjsLib); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
    s.onload = () => {
      window.pdfjsLib.GlobalWorkerOptions.workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
      resolve(window.pdfjsLib);
    };
    s.onerror = () => reject(new Error("Failed to load PDF.js"));
    document.head.appendChild(s);
  });
}

async function renderPage(pdfData, pageNum, scale = 2.0) {
  const lib = await loadPdfJs();
  const pdf = await lib.getDocument({ data: pdfData.slice(0) }).promise;
  const page = await pdf.getPage(pageNum);
  const vp = page.getViewport({ scale });
  const canvas = document.createElement("canvas");
  canvas.width = vp.width; canvas.height = vp.height;
  await page.render({ canvasContext: canvas.getContext("2d"), viewport: vp }).promise;
  return { base64: canvas.toDataURL("image/jpeg", 0.9).split(",")[1], totalPages: pdf.numPages };
}

async function getPdfPageCount(pdfData) {
  const lib = await loadPdfJs();
  const pdf = await lib.getDocument({ data: pdfData.slice(0) }).promise;
  return pdf.numPages;
}

function download(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a"); a.href = url; a.download = filename;
  document.body.appendChild(a); a.click();
  setTimeout(() => { URL.revokeObjectURL(url); document.body.removeChild(a); }, 100);
}

function exportCSV(allResults, filename) {
  const rows = [["Division","Name","Item","Detail","Location","Sheet"]];
  allResults.forEach(r => Object.entries(r.divisions||{}).sort(([a],[b])=>parseInt(a)-parseInt(b)).forEach(([num,div]) =>
    (div.items||[]).forEach(item => rows.push([num, div.name||"", item.item||"", item.detail||"", item.location||"", r.pageInfo||""]))));
  const csv = rows.map(r => r.map(c => `"${String(c).replace(/"/g,'\\""')}"`).join(",")).join("\n");
  download(new Blob([csv], {type:"text/csv"}), filename+".csv");
}

function exportHTML(allResults, projectName) {
  const merged = {};
  allResults.forEach(r => Object.entries(r.divisions||{}).forEach(([num,div]) => {
    if (!merged[num]) merged[num] = { name: div.name||CSI_DIVISIONS[num]||"", items:[] };
    (div.items||[]).forEach(item => merged[num].items.push({...item, sheet: r.pageInfo||""}));
  }));
  const total = Object.values(merged).reduce((s,d)=>s+(d.items?.length||0),0);
  const today = new Date().toLocaleDateString("en-US",{year:"numeric",month:"long",day:"numeric"});
  const divs = Object.entries(merged).sort(([a],[b])=>parseInt(a)-parseInt(b)).map(([num,div]) => {
    const color = DIV_COLORS[num]||"#8C7B6B";
    const rows = (div.items||[]).map(item => `<tr><td style="padding:8px 12px;border-bottom:1px solid #f0ebe4;font-size:12px;">${item.item||""}</td><td style="padding:8px 12px;border-bottom:1px solid #f0ebe4;font-size:12px;color:#6B5D50;">${item.detail||""}</td><td style="padding:8px 12px;border-bottom:1px solid #f0ebe4;font-size:12px;color:#9B8D80;">${item.location||""}</td><td style="padding:8px 12px;border-bottom:1px solid #f0ebe4;font-size:11px;color:#B8A898;">${item.sheet||""}</td></tr>`).join("");
    return `<div style="margin-bottom:16px;border:1px solid #D8CDBE;border-left:4px solid ${color};border-radius:4px;overflow:hidden;"><div style="background:#F7F2EB;padding:12px 16px;display:flex;justify-content:space-between;align-items:center;"><div style="display:flex;align-items:center;gap:12px;"><span style="background:${color};color:#fff;font-weight:700;font-size:11px;padding:3px 8px;border-radius:3px;font-family:monospace;">DIV ${num}</span><span style="font-weight:700;font-size:14px;color:#3D2E1E;">${div.name}</span></div><span style="font-size:12px;color:#8C7B6B;">${div.items.length} items</span></div><table style="width:100%;border-collapse:collapse;"><thead><tr style="background:#FBF8F4;"><th style="padding:8px 12px;text-align:left;font-size:10px;color:#9B8D80;font-weight:600;border-bottom:1px solid #D8CDBE;text-transform:uppercase;letter-spacing:1px;">Element</th><th style="padding:8px 12px;text-align:left;font-size:10px;color:#9B8D80;font-weight:600;border-bottom:1px solid #D8CDBE;text-transform:uppercase;letter-spacing:1px;">Specification</th><th style="padding:8px 12px;text-align:left;font-size:10px;color:#9B8D80;font-weight:600;border-bottom:1px solid #D8CDBE;text-transform:uppercase;letter-spacing:1px;">Location</th><th style="padding:8px 12px;text-align:left;font-size:10px;color:#9B8D80;font-weight:600;border-bottom:1px solid #D8CDBE;text-transform:uppercase;letter-spacing:1px;">Sheet</th></tr></thead><tbody>${rows}</tbody></table></div>`;
  }).join("");
  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>${projectName} — CSI Analysis</title><style>body{font-family:Georgia,serif;margin:0;padding:0;background:#FAF7F2;color:#3D2E1E;}.cover{background:linear-gradient(135deg,#3D2E1E,#5C4030);color:#FAF7F2;padding:56px 48px;text-align:center;}.cover h1{margin:0 0 8px;font-size:32px;}.cover p{opacity:0.6;font-size:13px;margin:4px 0;}.stats{display:flex;gap:40px;justify-content:center;margin-top:24px;}.stat .num{font-size:36px;font-weight:700;color:#D4A86A;}.stat .lbl{font-size:10px;opacity:0.6;letter-spacing:2px;text-transform:uppercase;}.body{padding:32px 48px;}</style></head><body><div class="cover"><div style="font-size:10px;letter-spacing:3px;color:#D4A86A;margin-bottom:12px;text-transform:uppercase;">CSI MasterFormat 2020 Analysis</div><h1>${projectName}</h1><p>Generated ${today} · CSI Division AI · Kaos Design Werks</p><div class="stats"><div class="stat"><div class="num">${Object.keys(merged).length}</div><div class="lbl">Divisions</div></div><div class="stat"><div class="num">${total}</div><div class="lbl">Items</div></div><div class="stat"><div class="num">${allResults.length}</div><div class="lbl">Pages</div></div></div></div><div class="body">${divs}</div></body></html>`;
  download(new Blob([html], {type:"text/html"}), projectName.replace(/\s+/g,"_")+"_CSI_Report.html");
}

const C = {
  cream:"#FAF7F2", warm1:"#F2EBE0", warm2:"#E8DDD0", warm3:"#D8CDBE",
  brown1:"#3D2E1E", brown2:"#5C4030", brown3:"#8C7B6B", brown4:"#B8A898",
  accent:"#D4A86A", accentDark:"#B88840",
};

function PageHeader({ title, sub, right }) {
  return (
    <div style={{ textAlign:"center", padding:"40px 24px 28px", borderBottom:`1px solid ${C.warm3}`, background:C.cream, position:"relative" }}>
      <img src={`data:image/png;base64,${LOGO_B64}`} alt="Kaos Design Werks"
        style={{ width:"72px", height:"72px", objectFit:"contain", borderRadius:"50%", marginBottom:"14px", display:"block", margin:"0 auto 14px" }} />
      <div style={{ fontFamily:"Georgia,serif", fontSize:"22px", fontWeight:"700", color:C.brown1, marginBottom:"3px", letterSpacing:"2px" }}>CSI DIVISION AI</div>
      <div style={{ fontSize:"11px", letterSpacing:"2px", color:C.brown4, textTransform:"uppercase" }}>Powered by Kaos Design Werks</div>
      {title && <div style={{ fontSize:"13px", color:C.brown3, marginTop:"6px" }}>{title}</div>}
      {right && <div style={{ position:"absolute", right:"20px", top:"50%", transform:"translateY(-50%)", display:"flex", gap:"8px" }}>{right}</div>}
    </div>
  );
}

export default function App() {
  const [stage, setStage] = useState("upload");
  const [pdfData, setPdfData] = useState(null);
  const [fileName, setFileName] = useState("");
  const [pageCount, setPageCount] = useState(0);
  const [pageThumbs, setPageThumbs] = useState({});
  const [selectedPages, setSelectedPages] = useState(new Set());
  const [loadingThumbs, setLoadingThumbs] = useState(false);
  const [progressCurrent, setProgressCurrent] = useState(0);
  const [progressTotal, setProgressTotal] = useState(0);
  const [progressMsg, setProgressMsg] = useState("");
  const [allResults, setAllResults] = useState([]);
  const [mergedDivisions, setMergedDivisions] = useState({});
  const [expandedDivs, setExpandedDivs] = useState({});
  const [projectName, setProjectName] = useState("");
  const [error, setError] = useState(null);
  const fileInputRef = useRef(null);
  const MAX_PAGES = 20;

  const processFile = async (f) => {
    if (!f.name.toLowerCase().endsWith(".pdf") && f.type !== "application/pdf") { setError("Please upload a PDF."); return; }
    setError(null); setLoadingThumbs(true); setFileName(f.name);
    setProjectName(f.name.replace(/\.pdf$/i,"").replace(/[_-]/g," "));
    try {
      const uint8 = new Uint8Array(await f.arrayBuffer());
      setPdfData(uint8);
      const count = await getPdfPageCount(uint8);
      setPageCount(count);
      const thumbs = {};
      for (let i = 1; i <= Math.min(6, count); i++) {
        const { base64 } = await renderPage(uint8, i, 0.4);
        thumbs[i] = base64;
      }
      setPageThumbs(thumbs); setSelectedPages(new Set()); setStage("select");
    } catch (e) { setError("Could not read PDF: " + e.message); }
    setLoadingThumbs(false);
  };

  const loadThumb = async (n) => {
    if (pageThumbs[n] || !pdfData) return;
    try { const { base64 } = await renderPage(pdfData, n, 0.4); setPageThumbs(p => ({...p, [n]:base64})); } catch {}
  };

  const togglePage = (n) => setSelectedPages(prev => {
    const next = new Set(prev);
    if (next.has(n)) next.delete(n); else if (next.size < MAX_PAGES) next.add(n);
    return next;
  });

  const selectAll = () => {
    const pages = Array.from({length: Math.min(pageCount, MAX_PAGES)}, (_,i) => i+1);
    setSelectedPages(new Set(pages)); pages.forEach(p => loadThumb(p));
  };

  const runAnalysis = async () => {
    if (selectedPages.size === 0) return;
    setStage("analyzing"); setError(null);
    const pages = Array.from(selectedPages).sort((a,b)=>a-b);
    setProgressTotal(pages.length); setProgressCurrent(0);
    const results = [];
    for (let i = 0; i < pages.length; i++) {
      const pageNum = pages[i];
      setProgressMsg(`Analyzing page ${pageNum}...`); setProgressCurrent(i);
      try {
        const { base64 } = await renderPage(pdfData, pageNum, 2.0);
        const res = await fetch("https://api.anthropic.com/v1/messages", {
          method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:4000, system:SYSTEM_PROMPT,
            messages:[{role:"user", content:[
              {type:"image", source:{type:"base64", media_type:"image/jpeg", data:base64}},
              {type:"text", text:`Analyze page ${pageNum}. Return only valid JSON.`}
            ]}]
          }),
        });
        if (!res.ok) { const e = await res.json(); throw new Error(e.error?.message||"API error"); }
        const data = await res.json();
        const text = data.content.map(b=>b.text||"").join("");
        const match = text.match(/\{[\s\S]*\}/);
        if (match) results.push({...JSON.parse(match[0]), _page:pageNum});
      } catch (e) { results.push({_page:pageNum, _error:e.message, divisions:{}}); }
      setProgressCurrent(i+1);
    }
    const merged = {};
    results.forEach(r => Object.entries(r.divisions||{}).forEach(([num,div]) => {
      if (!merged[num]) merged[num] = {name:div.name||CSI_DIVISIONS[num]||"", items:[]};
      (div.items||[]).forEach(item => merged[num].items.push({...item, _sheet:r.pageInfo||`Page ${r._page}`}));
    }));
    setAllResults(results); setMergedDivisions(merged);
    const exp = {}; Object.keys(merged).forEach(k=>(exp[k]=true)); setExpandedDivs(exp);
    setStage("results");
  };

  const reset = () => { setStage("upload"); setPdfData(null); setPageThumbs({}); setAllResults([]); setMergedDivisions({}); setSelectedPages(new Set()); };
  const totalItems = Object.values(mergedDivisions).reduce((s,d)=>s+(d.items?.length||0),0);
  const errorPages = allResults.filter(r=>r._error);

  const btnPrimary = (on) => ({
    background: on ? C.accent : C.warm3, color: on ? C.brown1 : C.brown4,
    border:"none", padding:"10px 22px", borderRadius:"4px", fontSize:"12px",
    fontWeight:"700", letterSpacing:"1px", cursor: on?"pointer":"not-allowed", fontFamily:"Georgia,serif",
  });
  const btnGhost = { background:"transparent", border:`1px solid ${C.warm3}`, color:C.brown3, padding:"8px 16px", borderRadius:"4px", fontSize:"11px", cursor:"pointer", fontFamily:"inherit" };
  const btnExport = (bg) => ({ background:bg, border:"none", color:"#fff", padding:"8px 14px", borderRadius:"4px", fontSize:"12px", fontWeight:"600", cursor:"pointer" });

  // ── UPLOAD ──
  if (stage === "upload") return (
    <div style={{minHeight:"100vh", background:C.cream, fontFamily:"Georgia,serif"}}>
      <PageHeader />
      <div style={{maxWidth:"560px", margin:"0 auto", padding:"56px 24px", textAlign:"center"}}>
        <div style={{fontSize:"11px", letterSpacing:"3px", textTransform:"uppercase", color:C.accent, marginBottom:"10px"}}>MasterFormat 2020</div>
        <h1 style={{margin:"0 0 12px", fontSize:"30px", fontWeight:"700", color:C.brown1}}>Analyze Your Construction Plans</h1>
        <p style={{margin:"0 0 40px", color:C.brown3, fontSize:"15px", lineHeight:"1.7"}}>Upload a PDF plan set. Select the pages you want analyzed. Get every element classified into the correct CSI division — downloadable as Excel, PDF, or Word.</p>
        <div
          onClick={()=>fileInputRef.current.click()}
          onDrop={(e)=>{e.preventDefault(); e.dataTransfer.files[0]&&processFile(e.dataTransfer.files[0]);}}
          onDragOver={(e)=>e.preventDefault()}
          style={{border:`2px dashed ${C.warm3}`, borderRadius:"10px", padding:"52px 32px", cursor:"pointer", background:C.warm1, transition:"all 0.2s", marginBottom:"28px"}}
          onMouseEnter={e=>{e.currentTarget.style.borderColor=C.accent; e.currentTarget.style.background="#F0E8D8";}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor=C.warm3; e.currentTarget.style.background=C.warm1;}}
        >
          <div style={{fontSize:"42px", marginBottom:"14px"}}>📄</div>
          <div style={{fontWeight:"700", color:C.brown1, marginBottom:"6px", fontSize:"16px"}}>Drop your PDF plan set here</div>
          <div style={{fontSize:"13px", color:C.brown4}}>or click to browse · up to {MAX_PAGES} pages per run</div>
          <input ref={fileInputRef} type="file" accept=".pdf,application/pdf" style={{display:"none"}} onChange={e=>e.target.files[0]&&processFile(e.target.files[0])} />
        </div>
        {loadingThumbs && <div style={{color:C.brown3, fontSize:"13px"}}>Loading PDF...</div>}
        {error && <div style={{background:"#FEF2F2", border:"1px solid #FECACA", borderRadius:"6px", padding:"12px 16px", color:"#DC2626", fontSize:"13px"}}>{error}</div>}
        <div style={{display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:"14px"}}>
          {[{icon:"🏗",label:"Floor Plans",desc:"Layouts, schedules, callouts"},{icon:"📐",label:"Details & Sections",desc:"Assemblies, connections"},{icon:"⚡",label:"MEP Plans",desc:"Electrical, plumbing, HVAC"}].map(c=>(
            <div key={c.label} style={{background:C.warm1, border:`1px solid ${C.warm3}`, borderRadius:"8px", padding:"18px 12px", textAlign:"center"}}>
              <div style={{fontSize:"24px", marginBottom:"8px"}}>{c.icon}</div>
              <div style={{fontWeight:"700", fontSize:"12px", color:C.brown1, marginBottom:"4px"}}>{c.label}</div>
              <div style={{fontSize:"11px", color:C.brown4}}>{c.desc}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  // ── SELECT ──
  if (stage === "select") {
    const pages = Array.from({length:pageCount},(_,i)=>i+1);
    return (
      <div style={{minHeight:"100vh", background:C.cream, fontFamily:"Georgia,serif"}}>
        <PageHeader title={`${fileName} · ${pageCount} pages`} right={[
          <button key="back" onClick={reset} style={btnGhost}>← New File</button>
        ]} />
        <div style={{maxWidth:"1100px", margin:"0 auto", padding:"28px 20px"}}>
          <div style={{display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:"20px", flexWrap:"wrap", gap:"12px"}}>
            <div>
              <input value={projectName} onChange={e=>setProjectName(e.target.value)} placeholder="Project Name"
                style={{fontSize:"20px", fontWeight:"700", color:C.brown1, border:"none", background:"transparent", outline:"none", fontFamily:"Georgia,serif", minWidth:"260px"}} />
              <div style={{fontSize:"11px", color:C.brown4, marginTop:"2px"}}>{selectedPages.size} of {pageCount} pages selected</div>
            </div>
            <div style={{display:"flex", gap:"8px"}}>
              <button onClick={selectAll} style={btnGhost}>Select All {pageCount>MAX_PAGES?`(max ${MAX_PAGES})`:""}</button>
              <button onClick={()=>setSelectedPages(new Set())} style={btnGhost}>Clear</button>
              <button onClick={runAnalysis} disabled={selectedPages.size===0} style={btnPrimary(selectedPages.size>0)}>
                ⚡ Analyze {selectedPages.size>0?`${selectedPages.size} Page${selectedPages.size>1?"s":""}` : ""}
              </button>
            </div>
          </div>
          <div style={{background:"#EFF6FF", border:"1px solid #BFDBFE", borderRadius:"6px", padding:"10px 16px", marginBottom:"20px", fontSize:"12px", color:"#1D4ED8"}}>
            💡 Click pages to select. You can select up to {MAX_PAGES} pages — pick just the sheets you need.
          </div>
          <div style={{display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))", gap:"12px"}}>
            {pages.map(n => {
              const sel = selectedPages.has(n);
              return (
                <div key={n} onClick={()=>{togglePage(n); loadThumb(n);}}
                  style={{border:`2px solid ${sel?C.accent:C.warm3}`, borderRadius:"8px", overflow:"hidden", cursor:"pointer", background:sel?"#F7F0E0":C.warm1, position:"relative", transition:"all 0.15s", boxShadow:sel?`0 0 0 3px rgba(212,168,106,0.2)`:"none"}}
                  onMouseEnter={e=>{if(!sel) e.currentTarget.style.borderColor=C.brown4;}}
                  onMouseLeave={e=>{if(!sel) e.currentTarget.style.borderColor=C.warm3;}}>
                  {sel && <div style={{position:"absolute", top:6, right:6, background:C.accent, color:C.brown1, borderRadius:"50%", width:20, height:20, display:"flex", alignItems:"center", justifyContent:"center", fontSize:"11px", fontWeight:"900", zIndex:2}}>✓</div>}
                  <div style={{background:C.warm2, height:"110px", display:"flex", alignItems:"center", justifyContent:"center", overflow:"hidden"}}>
                    {pageThumbs[n] ? <img src={`data:image/jpeg;base64,${pageThumbs[n]}`} alt={`Page ${n}`} style={{width:"100%", height:"100%", objectFit:"contain"}} />
                      : <div style={{color:C.brown4, fontSize:"11px"}} onClick={()=>loadThumb(n)}>Page {n}</div>}
                  </div>
                  <div style={{padding:"6px 8px", fontSize:"11px", fontWeight:"600", color:sel?C.brown2:C.brown3, textAlign:"center"}}>Page {n}</div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    );
  }

  // ── ANALYZING ──
  if (stage === "analyzing") {
    const pct = progressTotal>0 ? Math.round((progressCurrent/progressTotal)*100) : 0;
    return (
      <div style={{minHeight:"100vh", background:C.cream, fontFamily:"Georgia,serif", display:"flex", flexDirection:"column"}}>
        <PageHeader title="Classifying your plan..." />
        <div style={{flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:"40px 20px"}}>
          <div style={{maxWidth:"440px", width:"100%", textAlign:"center"}}>
            <div style={{fontSize:"48px", marginBottom:"20px"}}>🔍</div>
            <h2 style={{margin:"0 0 8px", fontSize:"22px", color:C.brown1}}>Analyzing Your Plan</h2>
            <p style={{color:C.brown3, fontSize:"14px", marginBottom:"32px"}}>{progressMsg}</p>
            <div style={{background:C.warm2, borderRadius:"99px", height:"8px", overflow:"hidden", marginBottom:"10px"}}>
              <div style={{background:`linear-gradient(90deg,${C.accentDark},${C.accent})`, height:"100%", width:`${pct}%`, borderRadius:"99px", transition:"width 0.4s ease"}} />
            </div>
            <div style={{fontSize:"13px", color:C.brown3}}><strong style={{color:C.brown1}}>{progressCurrent}</strong> of <strong style={{color:C.brown1}}>{progressTotal}</strong> pages · {pct}%</div>
          </div>
        </div>
      </div>
    );
  }

  // ── RESULTS ──
  const divEntries = Object.entries(mergedDivisions).sort(([a],[b])=>parseInt(a)-parseInt(b));
  return (
    <div style={{minHeight:"100vh", background:C.cream, fontFamily:"Georgia,serif"}}>
      <PageHeader
        title={projectName || "Analysis Results"}
        right={[
          <button key="csv" onClick={()=>exportCSV(allResults, projectName||"CSI_Analysis")} style={btnExport("#2D6A4F")}>📊 Excel</button>,
          <button key="html" onClick={()=>exportHTML(allResults, projectName||"CSI Analysis")} style={btnExport("#1E3A6E")}>📄 Report</button>,
          <button key="back" onClick={()=>setStage("select")} style={btnGhost}>← Back</button>,
          <button key="new" onClick={reset} style={btnGhost}>New File</button>,
        ]}
      />
      <div style={{maxWidth:"1200px", margin:"0 auto", padding:"24px 20px"}}>
        <div style={{display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:"14px", marginBottom:"24px"}}>
          {[
            {label:"Pages Analyzed", value:allResults.length, icon:"📄"},
            {label:"CSI Divisions", value:divEntries.length, icon:"📂"},
            {label:"Total Items", value:totalItems, icon:"📋"},
            {label:errorPages.length>0?"Page Errors":"All Pages OK", value:errorPages.length>0?errorPages.length:"✓", icon:errorPages.length>0?"⚠️":"✅"},
          ].map(c=>(
            <div key={c.label} style={{background:C.warm1, border:`1px solid ${C.warm3}`, borderRadius:"8px", padding:"20px", textAlign:"center"}}>
              <div style={{fontSize:"22px", marginBottom:"6px"}}>{c.icon}</div>
              <div style={{fontSize:"28px", fontWeight:"700", color:C.brown1, fontFamily:"Georgia,serif"}}>{c.value}</div>
              <div style={{fontSize:"11px", color:C.brown4, marginTop:"2px"}}>{c.label}</div>
            </div>
          ))}
        </div>
        <div style={{background:"#F0F9F4", border:"1px solid #BBF7D0", borderRadius:"6px", padding:"10px 16px", marginBottom:"20px", fontSize:"12px", color:"#166534"}}>
          💡 <strong>Excel</strong> opens in Excel — add a cost column next to each item. <strong>Report</strong> downloads a formatted HTML report — open in Word or print to PDF.
        </div>
        {divEntries.map(([num,div]) => {
          const color = DIV_COLORS[num]||C.brown3;
          const open = expandedDivs[num];
          return (
            <div key={num} style={{background:C.warm1, border:`1px solid ${C.warm3}`, borderLeft:`4px solid ${color}`, borderRadius:"6px", marginBottom:"8px", overflow:"hidden"}}>
              <div onClick={()=>setExpandedDivs(p=>({...p,[num]:!p[num]}))} style={{padding:"13px 18px", cursor:"pointer", display:"flex", justifyContent:"space-between", alignItems:"center", userSelect:"none"}}>
                <div style={{display:"flex", alignItems:"center", gap:"12px"}}>
                  <div style={{background:color, color:"#fff", fontWeight:"700", fontSize:"10px", padding:"3px 8px", borderRadius:"3px", minWidth:"34px", textAlign:"center", fontFamily:"monospace"}}>{num}</div>
                  <div style={{fontWeight:"700", fontSize:"14px", color:C.brown1}}>{div.name}</div>
                </div>
                <div style={{display:"flex", alignItems:"center", gap:"10px"}}>
                  <div style={{background:C.warm2, color:C.brown3, fontSize:"11px", fontWeight:"600", padding:"3px 10px", borderRadius:"99px"}}>{div.items.length} items</div>
                  <span style={{color:C.brown4, fontSize:"11px"}}>{open?"▲":"▼"}</span>
                </div>
              </div>
              {open && (
                <div style={{borderTop:`1px solid ${C.warm3}`}}>
                  <div style={{display:"grid", gridTemplateColumns:"1fr 1fr 180px 140px", padding:"6px 18px 6px 50px", background:C.warm2, fontSize:"9px", color:C.brown4, fontWeight:"700", letterSpacing:"1px", textTransform:"uppercase"}}>
                    <span>Element</span><span>Specification</span><span>Location</span><span>Sheet</span>
                  </div>
                  {div.items.map((item,idx)=>(
                    <div key={idx} style={{display:"grid", gridTemplateColumns:"1fr 1fr 180px 140px", padding:"10px 18px 10px 50px", borderBottom:idx<div.items.length-1?`1px solid ${C.cream}`:"none", alignItems:"start"}}>
                      <div style={{fontSize:"13px", fontWeight:"600", color:C.brown1, paddingRight:"12px"}}>{item.item}</div>
                      <div style={{fontSize:"12px", color:"#6B5D50", paddingRight:"12px"}}>{item.detail}</div>
                      <div style={{fontSize:"12px", color:C.brown4, fontStyle:"italic"}}>{item.location}</div>
                      <div style={{fontSize:"11px", color:C.warm3}}>{item._sheet}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
        {allResults.some(r=>r.uncategorized?.length>0) && (
          <div style={{background:C.warm1, border:`1px solid ${C.accent}`, borderLeft:`4px solid ${C.accent}`, borderRadius:"6px", padding:"16px 18px", marginTop:"8px"}}>
            <div style={{fontWeight:"700", fontSize:"13px", color:C.accentDark, marginBottom:"10px"}}>⚠ Items Needing Manual Review</div>
            {allResults.flatMap(r=>(r.uncategorized||[]).map(item=>({item, sheet:r.pageInfo||`Page ${r._page}`}))).map((x,i)=>(
              <div key={i} style={{fontSize:"12px", color:"#6B5D50", padding:"3px 0"}}>• {x.item} <span style={{color:C.accent}}>({x.sheet})</span></div>
            ))}
          </div>
        )}
        {errorPages.length>0 && (
          <div style={{background:"#FEF2F2", border:"1px solid #FECACA", borderRadius:"6px", padding:"14px 18px", marginTop:"8px"}}>
            <div style={{fontWeight:"700", fontSize:"13px", color:"#DC2626", marginBottom:"8px"}}>Pages That Could Not Be Analyzed</div>
            {errorPages.map((r,i)=>(<div key={i} style={{fontSize:"12px", color:"#B91C1C", padding:"2px 0"}}>• Page {r._page}: {r._error}</div>))}
          </div>
        )}
      </div>
    </div>
  );
}
